function autoFormatTime(O){let L=O['value']['replace'](/\D/g,'');switch(L['length']>0x4&&(L=L['slice'](0x0,0x4)),L['length']){case 0x0:case 0x1:case 0x2:O['value']=L;break;case 0x3:if(parseInt(L['slice'](0x0,0x2),0xa)<=0x17)O['value']=L['slice'](0x0,0x2)+':'+L['slice'](0x2);else{let J=L['slice'](0x0,0x1)['padStart'](0x2,'0'),v=L['slice'](0x1);O['value']=J+':'+v;}break;case 0x4:let y=L['slice'](0x0,0x2),X=L['slice'](0x2);O['value']=y+':'+X;}}function transformTimeValue(O){let L=O['trim']();if(/^\d{2}$/['test'](L))return L[0x0]['padStart'](0x2,'0')+':'+L[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](L))return 0x3===L['length']?parseInt(L['slice'](0x0,0x2),0xa)<=0x17?L['slice'](0x0,0x2)+':'+L['slice'](0x2):L['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+L['slice'](0x1):L['slice'](0x0,0x2)+':'+L['slice'](0x2);if(L['includes'](':')){let [y,X]=L['split'](':');return X||(X='00'),y=y['padStart'](0x2,'0'),X=X['padStart'](0x2,'0'),y+':'+X;}return L;}